#include <WiFi.h>
#include <FirebaseESP32.h>

#define WIFI_SSID "your_wifi_ssid"
#define WIFI_PASSWORD "your_wifi_password"
#define FIREBASE_HOST "your_firebase_project_id.firebaseio.com"
#define FIREBASE_AUTH "your_firebase_database_secret"

FirebaseData firebaseData;

void setup() {
  Serial.begin(115200);

  // Connect to Wi-Fi
  WiFi.begin(WIFI_SSID, WIFI_PASSWORD);
  while (WiFi.status() != WL_CONNECTED) {
    delay(1000);
    Serial.println("Connecting to WiFi...");
  }
  Serial.println("Connected to WiFi");

  // Initialize Firebase
  Firebase.begin(FIREBASE_HOST, FIREBASE_AUTH);

  // Set JSON data
  String jsonData = "{\"name\":\"John\",\"age\":30,\"city\":\"New York\"}";

  // Send JSON data to Firebase
  if (Firebase.pushString(firebaseData, "/users", jsonData)) {
    Serial.println("JSON data sent to Firebase");
  } else {
    Serial.println("Error sending JSON data to Firebase");
    Serial.println(firebaseData.errorReason());
  }
}

void loop() {
  // Nothing to do here
}
```
