{
    private GraphicsCaptureItem _captureItem;
    private GraphicsCaptureSession _session;
    private GraphicsCaptureSink _sink;
    private Rect _captureRegion;
}
```

---

## ✅ Part 3: Initialize the capture session with a custom region

```csharp
public async Task InitializeCaptureAsync(Rect region)
{
    _captureRegion = region;

    // Step 1: Create a capture picker
    var picker = new GraphicsCapturePicker();

    // Step 2: Let the user pick a region (this can be replaced with a fixed region)
    var item = await picker.PickSingleItemAsync();

    if (item == null)
        throw new InvalidOperationException("No region selected.");

    // Step 3: Create a subitem with the desired region
    _captureItem = item.CreateSubitem(_captureRegion);

    // Step 4: Create a capture sink to receive the frames
    _sink = _captureItem.CreateSink();

    // Step 5: Set up the sink
    await SetupSinkAsync();

    // Step 6: Create and start the capture session
    _session = _captureItem.CreateCaptureSession();
    await _session.StartCaptureAsync();
}
```

---

## ✅ Part 4: Setup the sink (frame format and output)

```csharp
private async Task SetupSinkAsync()
{
    // Set the desired frame size (e.g. 1920x1080)
    var frameSize = new Size(1920, 1080);

    // Set the desired pixel format (BGRA8888)
    var pixelFormat = BitmapPixelFormat.Bgra8;

    // Set the desired format for the sink
    _sink.SetDestinationSize(frameSize);
    _sink.SetPixelFormat(pixelFormat);
    _sink.SetRenderingEnabled(true);
    _sink.SetRecordingEnabled(true);

    // Optional: Set the frame rate
    await _sink.SetFrameRateAsync(30);
}
```

---

## ✅ Part 5: Capture and process frames

```csharp
public async Task CaptureFramesAsync()
{
    while (true)
    {
        // Get the next frame
        var frame = await _sink.GetNextFrameAsync();

        if (frame == null)
            break;

        // Convert the frame to a WritableBitmap
        var bitmap = new WriteableBitmap(
            (int)frame.ImageInformation.PixelWidth,
            (int)frame.ImageInformation.PixelHeight,
            96.0,
            96.0,
            PixelFormats.Bgra32,
            null);

        await bitmap.WritePixelsAsync(
            new Int32Rect(0, 0, (int)frame.ImageInformation.PixelWidth, (int)frame.ImageInformation.PixelHeight),
            frame.BitmapBuffer,
            0);

        // Do something with the bitmap (e.g. save, display, etc.)
        // For example, display it in an Image control
        // imageControl.Source = bitmap;
    }
}
```

