```php
use Kreait\Firebase\Factory;
use Kreait\Firebase\Messaging\CloudMessage;
use Kreait\Firebase\Messaging\Notification;
use Kreait\Firebase\Messaging\RegistrationToken;
use Kreait\Firebase\Auth\User;
use Kreait\Firebase\Auth\Request;
use Illuminate\Http\Request;
use Illuminate\Support\Facades\Validator;
use Illuminate\Support\Facades\Response;

class GuestUserController extends Controller
{
    public function signup(Request $request)
    {
        // 1. Validate the request
        $validator = Validator::make($request->all(), [
            'email' => 'required|email|unique:users,email',
            'password' => 'required|min:6',
        ]);

        if ($validator->fails()) {
            return response()->json(['error' => 'Validation failed', 'details' => $validator->errors()], 422);
        }

        $email = $request->input('email');
        $password = $request->input('password');

        // 2. Initialize Firebase
        $firebase = (new Factory)
            ->withServiceAccount(config('firebase.credentials'))
            ->withDatabaseUri(config('firebase.database_url'))
            ->create();

        // 3. Create a new user in Firebase Authentication
        $auth = $firebase->getAuth();
        $user = $auth->createUser([
            'email' => $email,
            'password' => $password,
        ]);

        // 4. Get the Firebase Instance ID Token (this is for FCM)
        // In a real app, the device token is usually sent from the client
        // For this example, we'll use a dummy token (you should get it from the client)
        $token = $request->input('device_token'); // This should be sent from the client

        // 5. Send a notification (optional)
        $message = CloudMessage::withTarget(RegistrationToken::fromValue($token))
            ->withNotification(Notification::create('Welcome!', 'You have been registered successfully.'));

        // You can send the message using the Firebase Messaging SDK
