#### 2. **Create a Policy Provider**

You can implement `IAuthorizationPolicyProvider` to load policies at runtime:

```csharp
public class CustomPolicyProvider : IAuthorizationPolicyProvider
{
    private readonly IAuthorizationPolicyProvider _defaultProvider;

    public CustomPolicyProvider(IAuthorizationPolicyProvider defaultProvider)
    {
        _defaultProvider = defaultProvider;
    }

    public Task<IAuthorizationPolicy> GetDefaultPolicyAsync()
    {
        return _defaultProvider.GetDefaultPolicyAsync();
    }

    public Task<IAuthorizationPolicy> GetPolicyAsync(string policyName)
    {
        // Load policy from external source (e.g., database, JSON, or API)
        var policy = LoadPolicyFromStore(policyName);

        if (policy == null)
        {
            return _defaultProvider.GetPolicyAsync(policyName);
        }

        return Task.FromResult(policy);
    }

    private IAuthorizationPolicy LoadPolicyFromStore(string policyName)
    {
        // Load policy from your external store
        // e.g., return a custom policy based on the JSON above
        // This is where you'd integrate with your IGA system or authorization service
        return new AuthorizationPolicyBuilder(policyName)
            .RequireClaim("Permission", policyName)
            .Build();
    }
}
```

