```csharp
using UnityEngine;
using System.IO;
using System.Runtime.Serialization.Formatters.Binary;

public class Example : MonoBehaviour
{
    public string filePath;

    private void SaveData(MyData data)
    {
        BinaryFormatter formatter = new BinaryFormatter();
        FileStream stream = new FileStream(filePath, FileMode.Create);
        formatter.Serialize(stream, data);
        stream.Close();
    }

    private MyData LoadData()
    {
        if (File.Exists(filePath))
        {
            BinaryFormatter formatter = new BinaryFormatter();
            FileStream stream = new FileStream(filePath, FileMode.Open);
            MyData data = formatter.Deserialize(stream) as MyData;
            stream.Close();
            return data;
        }
        else
        {
            Debug.LogError("File does not exist: " + filePath);
            return null;
        }
    }
}

[System.Serializable]
public class MyData
{
    public int score;
    public string playerName;
}
```
Here, we have a class called `Example` that contains two methods: `SaveData` and `LoadData`. The `SaveData` method takes an instance of the `MyData` class as a parameter, and uses the `BinaryFormatter` class to serialize it into binary data. The binary data is then written to a file using a `FileStream`. The `LoadData` method reads the binary data from the file and deserializes it back into an instance of the `MyData` class using the `BinaryFormatter`.

You'll notice the `MyData` class has the `[System.Serializable]` attribute, this is what tells Unity that this class should be serialized and deserialized.

In order to use this code, you'll need to set the `filePath` variable to the path where you want to save the data file, for example: `"Assets/Data/save.dat"`. And then you can call the `SaveData(data)` and `LoadData()` methods as needed during your game.

